use std::collections::{HashSet, BTreeSet};

fn even_squares(iter: impl Iterator<Item = i32>) -> Vec<i32> {
    iter.filter(|&x| x % 2 == 0)
        .map(|x| x * x)
        .collect()
}

// When the collection type is ambiguous, use turbofish or type annotation:
fn to_collection<C>(iter: impl Iterator<Item = i32>) -> C
where
    C: FromIterator<i32>,
{
    iter.collect()
}

fn deduplicate(iter: impl Iterator<Item = i32>) -> Vec<i32> {
    // Collect into HashSet then back to Vec to deduplicate:
    let set: HashSet<i32> = iter.collect();
    let mut v: Vec<i32> = set.into_iter().collect();
    v.sort();
    v
}

fn main() {
    let v = vec![1, 2, 3, 4, 5, 6, 4, 2];
    println!("{:?}", even_squares(v.iter().copied()));

    let set: HashSet<i32> = to_collection(v.iter().copied());
    println!("unique count: {}", set.len());

    let sorted: BTreeSet<i32> = to_collection(v.iter().copied());
    println!("sorted unique: {:?}", sorted);

    println!("deduped: {:?}", deduplicate(v.iter().copied()));
}

