use std::io::{self, Read, Write, BufReader, BufWriter};

fn pipe(src: impl Read, dst: impl Write) -> io::Result<u64> {
    let mut src = BufReader::new(src);
    let mut dst = BufWriter::new(dst);
    let n = io::copy(&mut src, &mut dst)?;
    dst.flush()?;
    Ok(n)
}

fn tee(src: impl Read, mut a: impl Write, mut b: impl Write) -> io::Result<u64> {
    let mut buf = vec![0u8; 4096];
    let mut total = 0u64;
    let mut src = src;
    loop {
        let n = src.read(&mut buf)?;
        if n == 0 { break; }
        a.write_all(&buf[..n])?;
        b.write_all(&buf[..n])?;
        total += n as u64;
    }
    Ok(total)
}

fn main() -> io::Result<()> {
    use std::io::Cursor;
    let input = Cursor::new(b"hello, Rust!".to_vec());
    let mut out1 = Vec::new();
    let mut out2 = Vec::new();
    tee(input, &mut out1, &mut out2)?;
    println!("out1: {:?}", String::from_utf8(out1).unwrap());
