pub fn transform_all<T, U>(items: Vec<T>, transform: impl Fn(T) -> U) -> Vec<U> {
    items.into_iter().map(transform).collect()
}

// Even cleaner for both input and output with full impl Trait:
pub fn map_display(items: impl IntoIterator<Item = impl std::fmt::Display>) -> Vec<String> {
    items.into_iter().map(|x| x.to_string()).collect()
}

pub fn filter_map_parse<T>(items: impl IntoIterator<Item = impl AsRef<str>>) -> Vec<T>
where
    T: std::str::FromStr,
{
    items.into_iter()
        .filter_map(|s| s.as_ref().parse().ok())
        .collect()
}

fn main() {
    let doubled = transform_all(vec![1i32, 2, 3], |x| x * 2);
    println!("{:?}", doubled);

    let strs = map_display(vec![1i32, 2, 3]);
    println!("{:?}", strs);

    let parsed: Vec<i32> = filter_map_parse(vec!["1", "bad", "3", "4"]);
    println!("{:?}", parsed);
}

