use std::fmt;

trait Processor {
    fn process(&self, input: impl fmt::Display) -> String;
    fn process_all(&self, items: impl IntoIterator<Item = impl fmt::Display>) -> Vec<String> {
        items.into_iter()
            .map(|item| self.process(item))
            .collect()
    }
}

struct Upper;
struct Lower;
struct Prefix(String);

impl Processor for Upper {
    fn process(&self, input: impl fmt::Display) -> String {
        format!("{}", input).to_uppercase()
    }
}

impl Processor for Lower {
    fn process(&self, input: impl fmt::Display) -> String {
        format!("{}", input).to_lowercase()
    }
}

impl Processor for Prefix {
    fn process(&self, input: impl fmt::Display) -> String {
        format!("{}{}", self.0, input)
    }
}

fn main() {
    let u = Upper;
    let l = Lower;
    let p = Prefix(String::from(">> "));

    println!("{}", u.process("hello"));
    println!("{}", l.process("WORLD"));
    println!("{}", p.process(42));
    println!("{:?}", u.process_all(["alpha", "beta", "gamma"]));
}

