use std::cmp::Ordering;

fn custom_sort<T>(data: &mut [T], cmp: impl Fn(&T, &T) -> Ordering) {
    data.sort_by(|a, b| cmp(a, b));
}

// Helper to convert a less-than predicate to Ordering:
fn sort_by_lt<T>(data: &mut [T], lt: impl Fn(&T, &T) -> bool) {
    data.sort_by(|a, b| {
        if lt(a, b) { Ordering::Less }
        else if lt(b, a) { Ordering::Greater }
        else { Ordering::Equal }
    });
}

fn sort_by_key_fn<T, K: Ord>(data: &mut [T], key: impl Fn(&T) -> K) {
    data.sort_by_key(|item| key(item));
}

fn main() {
    let mut v = vec![3i32, 1, 4, 1, 5, 9, 2, 6];
    custom_sort(&mut v, i32::cmp);
    println!("asc: {:?}", v);

    custom_sort(&mut v, |a, b| b.cmp(a));
    println!("desc: {:?}", v);

    let mut words = vec!["banana", "apple", "cherry"];
    sort_by_key_fn(&mut words, |s| s.len());
    println!("by len: {:?}", words);

    sort_by_lt(&mut v, |a, b| a < b);
    println!("lt asc: {:?}", v);
}

