fn format_pair(a: impl fmt::Display, b: impl fmt::Debug) -> String {
    format!("({}, {:?})", a, b)
}

// When both args should contribute, use them:
fn join_display(a: impl fmt::Display, sep: impl fmt::Display, b: impl fmt::Display) -> String {
    format!("{}{}{}", a, sep, b)
}

// If only one arg is used, consider accepting just that one:
fn show_first(x: impl fmt::Display) -> String {
    format!("{}", x)
}

// Or use a slice for a variadic-like API:
fn join_all(items: &[impl fmt::Display], sep: &str) -> String {
    // Unfortunately &[impl Display] not allowed — use named generic:
    // items.iter().map(|x| format!("{}", x)).collect::<Vec<_>>().join(sep)
    sep.to_owned() // placeholder
}

fn main() {
    println!("{}", format_pair(42i32, "debug"));
    println!("{}", join_display("hello", ", ", "world"));
    println!("{}", show_first(99u8));
}

