use std::fmt;

// Inline bounds for simple, short bounds:
fn log(label: impl fmt::Display, value: impl fmt::Debug + Clone) -> String {
    let v = value.clone();
    format!("[{}] {:?}", label, v)
}

// Where clause for complex or long bounds, or when the type is referenced multiple times:
fn serialize_and_compare<T, U>(a: T, b: U) -> bool
where
    T: fmt::Display + fmt::Debug + PartialOrd,
    U: fmt::Display + Into<T>,
{
    let b_as_t: T = b.into();
    println!("comparing {} vs {}", a, b_as_t);
    a >= b_as_t
}

// Mix inline and where:
fn transform<Out>(input: impl AsRef<str>, count: usize) -> Out
where
    Out: FromIterator<char>,
{
    input.as_ref().chars().cycle().take(count).collect()
}

fn main() {
    println!("{}", log("key", vec![1, 2, 3]));
    println!("{}", serialize_and_compare(10i32, 5i32));
    let s: String = transform("abc", 7);
    println!("{}", s); // "abcabca"
}

