use std::fmt;

// Named generic: both params are the SAME concrete type T
fn pair_same<T: fmt::Display>(a: T, b: T) {
    println!("same type: {} {}", a, b);
}

// impl Trait: each param is an INDEPENDENT anonymous generic
fn pair_any(a: impl fmt::Display, b: impl fmt::Display) {
    println!("any types: {} {}", a, b);
}

// Named generic required when T appears in return type:
fn identity<T: fmt::Display>(val: T) -> T { val }

// Named generic required for turbofish:
fn parse_and_display<T: std::str::FromStr + fmt::Display>(s: &str) -> String
where T::Err: fmt::Debug
{
    format!("{}", s.parse::<T>().unwrap())
}

fn main() {
    pair_same(1i32, 2);     // both i32
    // pair_same(1i32, 'x'); -- ERROR: different types
    pair_any(1i32, 'x');    // OK: independent types
    pair_any("hello", 42.0f64);

    let n: i32 = identity(42);
    println!("{}", n);

    println!("{}", parse_and_display::<f64>("3.14"));
}
